    96	// handleUpdate responds to changes in the api-gateway. In general, we want
    97	// to crawl the various resources related to or attached to the gateway and
    98	// collect the list of things need to generate xDS.  This list of resources
    99	// includes the bound-api-gateway, http-routes, tcp-routes, and inline-certificates.
   100	func (h *handlerAPIGateway) handleUpdate(ctx context.Context, u UpdateEvent, snap *ConfigSnapshot) error {
   101		if u.Err != nil {
   102			return fmt.Errorf("error filling agent cache: %v", u.Err)
   103		}
   104	
   105		switch u.CorrelationID {
   106		case rootsWatchID:
   107			// Handle change in the CA roots
   108			if err := h.handleRootCAUpdate(u, snap); err != nil {
   109				return err
   110			}
   111		case apiGatewayConfigWatchID, boundGatewayConfigWatchID:
   112			// Handle change in the api-gateway or bound-api-gateway config entry
   113			if err := h.handleGatewayConfigUpdate(ctx, u, snap, u.CorrelationID); err != nil {
   114				return err
   115			}
   116		case inlineCertificateConfigWatchID:
   117			// Handle change in an attached inline-certificate config entry
   118			if err := h.handleInlineCertConfigUpdate(ctx, u, snap); err != nil {
   119				return err
   120			}
   121		case routeConfigWatchID:
   122			// Handle change in an attached http-route or tcp-route config entry
   123			if err := h.handleRouteConfigUpdate(ctx, u, snap); err != nil {
   124				return err
   125			}
   126		case jwtProviderID:
   127			err := setJWTProvider(u, snap)
   128			if err != nil {
   129				return err
   130			}
   131	
   132		default:
   133			if err := (*handlerUpstreams)(h).handleUpdateUpstreams(ctx, u, snap); err != nil {
   134				return err
   135			}
   136		}
   137	
   138		return h.recompileDiscoveryChains(snap)
   139	}
