   293	// handleRouteConfigUpdate builds the list of upstreams for services on
   294	// the route and watches the related discovery chains.
   295	func (h *handlerAPIGateway) handleRouteConfigUpdate(ctx context.Context, u UpdateEvent, snap *ConfigSnapshot) error {
   296		resp, ok := u.Result.(*structs.ConfigEntryResponse)
   297		if !ok {
   298			return fmt.Errorf("invalid type for response: %T", u.Result)
   299		} else if resp.Entry == nil {
   300			return nil
   301		}
   302	
   303		ref := structs.ResourceReference{
   304			Kind:           resp.Entry.GetKind(),
   305			Name:           resp.Entry.GetName(),
   306			EnterpriseMeta: *resp.Entry.GetEnterpriseMeta(),
   307		}
   308	
   309		seenUpstreamIDs := make(upstreamIDSet)
   310		upstreams := make(map[APIGatewayListenerKey]structs.Upstreams)
   311	
   312		switch route := resp.Entry.(type) {
   313		case *structs.HTTPRouteConfigEntry:
   314			snap.APIGateway.HTTPRoutes.Set(ref, route)
   315	
   316			for _, rule := range route.Rules {
   317				for _, service := range rule.Services {
   318					for _, listener := range snap.APIGateway.Listeners {
   319						shouldBind := false
   320						for _, parent := range route.Parents {
   321							if h.referenceIsForListener(parent, listener, snap) {
   322								shouldBind = true
   323								break
   324							}
   325						}
   326						if !shouldBind {
   327							continue
   328						}
   329	
   330						upstream := structs.Upstream{
   331							DestinationName:      service.Name,
   332							DestinationNamespace: service.NamespaceOrDefault(),
   333							DestinationPartition: service.PartitionOrDefault(),
   334							LocalBindPort:        listener.Port,
   335							// Pass the protocol that was configured on the listener in order
   336							// to force that protocol on the Envoy listener.
   337							Config: map[string]interface{}{
   338								"protocol": "http",
   339							},
   340						}
   341	
   342						listenerKey := APIGatewayListenerKeyFromListener(listener)
   343						upstreams[listenerKey] = append(upstreams[listenerKey], upstream)
   344					}
   345	
   346					upstreamID := NewUpstreamIDFromServiceName(service.ServiceName())
   347					seenUpstreamIDs[upstreamID] = struct{}{}
   348	
   349					watchOpts := discoveryChainWatchOpts{
   350						id:         upstreamID,
   351						name:       service.Name,
   352						namespace:  service.NamespaceOrDefault(),
   353						partition:  service.PartitionOrDefault(),
   354						datacenter: h.stateConfig.source.Datacenter,
   355					}
   356	
   357					handler := &handlerUpstreams{handlerState: h.handlerState}
   358					if err := handler.watchDiscoveryChain(ctx, snap, watchOpts); err != nil {
   359						return fmt.Errorf("failed to watch discovery chain for %s: %w", upstreamID, err)
   360					}
   361				}
   362			}
   363	
   364		case *structs.TCPRouteConfigEntry:
   365			snap.APIGateway.TCPRoutes.Set(ref, route)
   366	
   367			for _, service := range route.Services {
   368				upstreamID := NewUpstreamIDFromServiceName(service.ServiceName())
   369				seenUpstreamIDs.add(upstreamID)
   370	
   371				// For each listener, check if this route should bind and, if so, create an upstream.
   372				for _, listener := range snap.APIGateway.Listeners {
   373					shouldBind := false
   374					for _, parent := range route.Parents {
   375						if h.referenceIsForListener(parent, listener, snap) {
   376							shouldBind = true
   377							break
   378						}
   379					}
   380					if !shouldBind {
   381						continue
   382					}
   383	
   384					upstream := structs.Upstream{
   385						DestinationName:      service.Name,
   386						DestinationNamespace: service.NamespaceOrDefault(),
   387						DestinationPartition: service.PartitionOrDefault(),
   388						LocalBindPort:        listener.Port,
   389						// Pass the protocol that was configured on the ingress listener in order
   390						// to force that protocol on the Envoy listener.
   391						Config: map[string]interface{}{
   392							"protocol": "tcp",
   393						},
   394					}
   395	
   396					listenerKey := APIGatewayListenerKeyFromListener(listener)
   397					upstreams[listenerKey] = append(upstreams[listenerKey], upstream)
   398				}
   399	
   400				watchOpts := discoveryChainWatchOpts{
   401					id:         upstreamID,
   402					name:       service.Name,
   403					namespace:  service.NamespaceOrDefault(),
   404					partition:  service.PartitionOrDefault(),
   405					datacenter: h.stateConfig.source.Datacenter,
   406				}
   407	
   408				handler := &handlerUpstreams{handlerState: h.handlerState}
   409				if err := handler.watchDiscoveryChain(ctx, snap, watchOpts); err != nil {
   410					return fmt.Errorf("failed to watch discovery chain for %s: %w", upstreamID, err)
   411				}
   412			}
   413		default:
   414			return fmt.Errorf("invalid type for config entry: %T", resp.Entry)
   415		}
   416	
   417		for listener, set := range upstreams {
   418			snap.APIGateway.Upstreams.set(ref, listener, set)
   419		}
   420		snap.APIGateway.UpstreamsSet.set(ref, seenUpstreamIDs)
   421	
   422		// Stop watching any upstreams and discovery chains that have become irrelevant
   423		for upstreamID, cancelDiscoChain := range snap.APIGateway.WatchedDiscoveryChains {
   424			if snap.APIGateway.UpstreamsSet.hasUpstream(upstreamID) {
   425				continue
   426			}
   427	
   428			for targetID, cancelUpstream := range snap.APIGateway.WatchedUpstreams[upstreamID] {
   429				cancelUpstream()
   430				delete(snap.APIGateway.WatchedUpstreams[upstreamID], targetID)
   431				delete(snap.APIGateway.WatchedUpstreamEndpoints[upstreamID], targetID)
   432	
   433				if targetUID := NewUpstreamIDFromTargetID(targetID); targetUID.Peer != "" {
   434					snap.APIGateway.PeerUpstreamEndpoints.CancelWatch(targetUID)
   435					snap.APIGateway.UpstreamPeerTrustBundles.CancelWatch(targetUID.Peer)
   436				}
   437			}
   438	
   439			cancelDiscoChain()
   440			delete(snap.APIGateway.WatchedDiscoveryChains, upstreamID)
   441		}
   442	
   443		return nil
   444	}
   445	
   446	func (h *handlerAPIGateway) recompileDiscoveryChains(snap *ConfigSnapshot) error {
   447		synthesizedChains := map[UpstreamID]*structs.CompiledDiscoveryChain{}
   448	
   449		for name, listener := range snap.APIGateway.Listeners {
   450			boundListener, ok := snap.APIGateway.BoundListeners[name]
   451			if !(ok && snap.APIGateway.GatewayConfig.ListenerIsReady(name)) {
   452				// Skip any listeners that don't have a bound listener. Once the bound listener is created, this will be run again.
   453				// skip any listeners that might be in an invalid state
   454				continue
   455			}
   456	
   457			// Create a synthesized discovery chain for each service.
   458			services, upstreams, compiled, err := snap.APIGateway.synthesizeChains(h.source.Datacenter, listener, boundListener)
   459			if err != nil {
   460				return err
   461			}
   462	
   463			if len(upstreams) == 0 {
   464				// skip if we can't construct any upstreams
   465				continue
   466			}
   467	
   468			for i, service := range services {
   469				id := NewUpstreamIDFromServiceName(structs.NewServiceName(service.Name, &service.EnterpriseMeta))
   470	
   471				if compiled[i].ServiceName != service.Name {
   472					return fmt.Errorf("Compiled Discovery chain for %s does not match service %s", compiled[i].ServiceName, id)
   473				}
   474				synthesizedChains[id] = compiled[i]
   475			}
   476		}
   477	
   478		// Merge in additional discovery chains
   479		for id, chain := range synthesizedChains {
   480			snap.APIGateway.DiscoveryChain[id] = chain
   481		}
   482	
   483		return nil
   484	}
   485	
   486	// referenceIsForListener returns whether the provided structs.ResourceReference
   487	// targets the provided structs.APIGatewayListener. For this to be true, the kind
   488	// and name must match the structs.APIGatewayConfigEntry containing the listener,
   489	// and the reference must specify either no section name or the name of the listener
   490	// as the section name.
   491	//
   492	// TODO This would probably be more generally useful as a helper in the structs pkg
   493	func (h *handlerAPIGateway) referenceIsForListener(ref structs.ResourceReference, listener structs.APIGatewayListener, snap *ConfigSnapshot) bool {
   494		if ref.Kind != structs.APIGateway && ref.Kind != "" {
   495			return false
   496		}
   497		if ref.Name != snap.APIGateway.GatewayConfig.Name {
   498			return false
   499		}
   500		return ref.SectionName == "" || ref.SectionName == listener.Name
   501	}
   502	
   503	func (h *handlerAPIGateway) watchIngressLeafCert(ctx context.Context, snap *ConfigSnapshot) error {
   504		// Note that we DON'T test for TLS.enabled because we need a leaf cert for the
   505		// gateway even without TLS to use as a client cert.
   506		if !snap.APIGateway.GatewayConfigLoaded {
   507			return nil
   508		}
   509	
   510		// Watch the leaf cert
   511		if snap.APIGateway.LeafCertWatchCancel != nil {
   512			snap.APIGateway.LeafCertWatchCancel()
   513		}
   514		ctx, cancel := context.WithCancel(ctx)
   515		err := h.dataSources.LeafCertificate.Notify(ctx, &leafcert.ConnectCALeafRequest{
   516			Datacenter:     h.source.Datacenter,
   517			Token:          h.token,
   518			Service:        h.service,
   519			EnterpriseMeta: h.proxyID.EnterpriseMeta,
   520		}, leafWatchID, h.ch)
   521		if err != nil {
   522			cancel()
   523			return err
   524		}
   525		snap.APIGateway.LeafCertWatchCancel = cancel
   526	
   527		return nil
   528	}
