//go:build ignore
// +build ignore

package main

import (
	"fmt"

	"github.com/hashicorp/consul/agent/structs"
)

func main() {
	// Test that we can create a FileSystemCertificateConfigEntry
	entry := &structs.FileSystemCertificateConfigEntry{
		Kind:        structs.FileSystemCertificate,
		Name:        "test-cert",
		Certificate: "/path/to/cert.pem",
		PrivateKey:  "/path/to/key.pem",
		Meta: map[string]string{
			"env": "test",
		},
	}

	// Test GetKind
	if entry.GetKind() != structs.FileSystemCertificate {
		fmt.Printf("FAIL: GetKind() = %q, want %q\n", entry.GetKind(), structs.FileSystemCertificate)
		return
	}

	// Test GetName
	if entry.GetName() != "test-cert" {
		fmt.Printf("FAIL: GetName() = %q, want %q\n", entry.GetName(), "test-cert")
		return
	}

	// Test validation with valid entry (paths, empty paths should be OK)
	if err := entry.Validate(); err != nil {
		fmt.Printf("FAIL: Validate() = %v, want nil\n", err)
		return
	}

	// Test validation with empty paths (should be OK per spec)
	emptyEntry := &structs.FileSystemCertificateConfigEntry{
		Kind: structs.FileSystemCertificate,
		Name: "empty-test",
	}
	if err := emptyEntry.Validate(); err != nil {
		fmt.Printf("FAIL: Validate() for empty paths = %v, want nil\n", err)
		return
	}

	// Test DeepCopy
	copy := entry.DeepCopy()
	if copy.Name != entry.Name || copy.Certificate != entry.Certificate {
		fmt.Printf("FAIL: DeepCopy() did not copy correctly\n")
		return
	}

	// Test MakeConfigEntry
	created, err := structs.MakeConfigEntry(structs.FileSystemCertificate, "created")
	if err != nil {
		fmt.Printf("FAIL: MakeConfigEntry() = %v, want nil\n", err)
		return
	}
	if created.GetKind() != structs.FileSystemCertificate {
		fmt.Printf("FAIL: MakeConfigEntry().GetKind() = %q, want %q\n", created.GetKind(), structs.FileSystemCertificate)
		return
	}

	fmt.Println("PASS: All tests passed!")
}
