package main

import (
	"fmt"

	envoy_tls_v3 "github.com/envoyproxy/go-control-plane/envoy/extensions/transport_sockets/tls/v3"
	envoy_core_v3 "github.com/envoyproxy/go-control-plane/envoy/config/core/v3"
)

func main() {
	// Test that we can create an Envoy Secret with file paths
	secret := &envoy_tls_v3.Secret{
		Name: "test-cert",
		Type: &envoy_tls_v3.Secret_TlsCertificate{
			TlsCertificate: &envoy_tls_v3.TlsCertificate{
				CertificateChain: &envoy_core_v3.DataSource{
					Specifier: &envoy_core_v3.DataSource_Filename{
						Filename: "/path/to/cert.pem",
					},
				},
				PrivateKey: &envoy_core_v3.DataSource{
					Specifier: &envoy_core_v3.DataSource_Filename{
						Filename: "/path/to/key.pem",
					},
				},
			},
		},
	}

	// Verify the secret was created correctly
	if secret.Name != "test-cert" {
		fmt.Printf("FAIL: secret.Name = %q, want %q\n", secret.Name, "test-cert")
		return
	}

	tlsCert := secret.GetTlsCertificate()
	if tlsCert == nil {
		fmt.Printf("FAIL: GetTlsCertificate() = nil\n")
		return
	}

	certChain := tlsCert.GetCertificateChain()
	if certChain == nil {
		fmt.Printf("FAIL: GetCertificateChain() = nil\n")
		return
	}

	filename := certChain.GetFilename()
	if filename != "/path/to/cert.pem" {
		fmt.Printf("FAIL: GetFilename() = %q, want %q\n", filename, "/path/to/cert.pem")
		return
	}

	fmt.Println("PASS: All xDS secrets tests passed!")
}
